    <style>
        *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

        body {
            font-family: 'Plus Jakarta Sans', sans-serif;
            min-height: 100vh;
            display: flex;
            align-items: center;
            justify-content: center;
            padding: 20px;
            background: linear-gradient(145deg, #eff6ff 0%, #f8fafc 45%, #f0f9ff 100%);
            -webkit-font-smoothing: antialiased;
        }

        /* ── Shell ─── */
        .shell {
            width: 100%;
            max-width: 980px;
            display: flex;
            border-radius: 24px;
            overflow: hidden;
            box-shadow: 0 32px 80px rgba(0,0,0,.5), 0 0 0 1px rgba(255,255,255,.06);
        }

        /* ── Left panel ─── */
        .left {
            width: 42%;
            position: relative;
            overflow: hidden;
            flex-shrink: 0;
        }
        @media(max-width:780px){ .left { display: none; } .shell { max-width: 500px; } }

        .left-img {
            position: absolute;
            inset: 0;
            background: url('data:image/png;base64,') center/cover no-repeat;
        }
        .left-overlay {
            position: absolute;
            inset: 0;
            background: linear-gradient(170deg, rgba(15,23,42,.55) 0%, rgba(15,23,42,.28) 40%, rgba(15,23,42,.82) 100%);
        }
        .left-content {
            position: relative;
            z-index: 2;
            height: 100%;
            display: flex;
            flex-direction: column;
            justify-content: space-between;
            padding: 28px 30px;
        }
        .left-brand { display: flex; align-items: center; gap: 10px; }
        .left-logo {
            width: 38px; height: 38px;
            background: rgba(255,255,255,.15);
            border: 1.5px solid rgba(255,255,255,.28);
            border-radius: 11px;
            display: flex; align-items: center; justify-content: center;
            font-size: 16px; font-weight: 900; color: #fff;
            backdrop-filter: blur(4px);
        }
        .left-brand-name { font-size: 15px; font-weight: 800; color: #fff; letter-spacing: -.02em; }
        .left-brand-sub  { font-size: 10.5px; color: rgba(255,255,255,.55); font-weight: 500; }

        .left-bottom {}
        .loc-tag {
            display: inline-flex; align-items: center; gap: 5px;
            background: rgba(255,255,255,.1); border: 1px solid rgba(255,255,255,.18);
            backdrop-filter: blur(6px);
            padding: 4px 10px; border-radius: 20px;
            font-size: 10px; color: rgba(255,255,255,.7); font-weight: 600;
            margin-bottom: 12px;
        }
        .loc-tag svg { width: 10px; height: 10px; }
        .left-caption {
            font-size: 20px; font-weight: 900; color: #fff;
            line-height: 1.25; letter-spacing: -.03em; margin-bottom: 16px;
        }
        .left-caption span { color: #93c5fd; }
        .left-features { display: flex; flex-direction: column; gap: 9px; }
        .feat { display: flex; align-items: center; gap: 8px; }
        .feat-dot {
            width: 19px; height: 19px;
            background: rgba(255,255,255,.13); border: 1px solid rgba(255,255,255,.22);
            border-radius: 6px; display: flex; align-items: center; justify-content: center;
            flex-shrink: 0; backdrop-filter: blur(4px);
        }
        .feat-dot svg { width: 10px; height: 10px; color: #93c5fd; }
        .feat span { font-size: 11.5px; color: rgba(255,255,255,.78); font-weight: 500; }

        /* ── Right panel ─── */
        .right {
            flex: 1;
            background: #fff;
            display: flex;
            flex-direction: column;
            justify-content: center;
            padding: 32px 36px;
            overflow-y: auto;
            max-height: 100vh;
        }
        @media(max-width:480px){ .right { padding: 28px 20px; } }

        /* Form header */
        .form-eyebrow {
            font-size: 10px; font-weight: 800; color: #2563eb;
            text-transform: uppercase; letter-spacing: .08em; margin-bottom: 5px;
        }
        .form-title {
            font-size: 22px; font-weight: 900; color: #0f172a;
            letter-spacing: -.04em; line-height: 1.15; margin-bottom: 3px;
        }
        .form-sub { font-size: 12.5px; color: #94a3b8; font-weight: 500; margin-bottom: 20px; }

        /* Error box */
        .error-box {
            display: flex; gap: 9px; align-items: flex-start;
            background: #fef2f2; border: 1.5px solid #fecaca;
            border-radius: 12px; padding: 10px 12px; margin-bottom: 16px;
        }
        .error-box svg { width: 14px; height: 14px; stroke: #ef4444; flex-shrink: 0; margin-top: 1px; }
        .error-box ul { list-style: none; }
        .error-box li { font-size: 12px; color: #dc2626; line-height: 1.5; }

        /* Fields */
        .field { margin-bottom: 12px; }
