        .iw { position: relative; display: flex; align-items: center; }
        .iw-icon {
            position: absolute; left: 10px; z-index: 1; pointer-events: none;
            width: 28px; height: 28px; border-radius: 8px;
            display: flex; align-items: center; justify-content: center;
        }
        .iw-icon svg { width: 13px; height: 13px; fill: none; }
        .iw-icon.blue  { background: #eff6ff; } .iw-icon.blue  svg { stroke: #3b82f6; }
        .iw-icon.green { background: #f0fdf4; } .iw-icon.green svg { stroke: #22c55e; }
        .iw-icon.amber { background: #fffbeb; } .iw-icon.amber svg { stroke: #f59e0b; }

        .iw input, .iw select {
            width: 100%; padding: 10px 13px 10px 46px;
            font-size: 13px; color: #111827; font-family: inherit;
            background: #f9fafb; border: 1.5px solid #e5e7eb;
            border-radius: 11px; outline: none;
            transition: border-color .15s, background .15s, box-shadow .15s;
            -webkit-appearance: none; appearance: none;
        }
        .iw input::placeholder { color: #9ca3af; font-size: 12.5px; }
        .iw input:focus, .iw select:focus {
            border-color: #3b82f6; background: #fff;
            box-shadow: 0 0 0 3px rgba(59,130,246,.12);
        }
        .iw input.err { border-color: #fca5a5; background: #fef2f2; }
        .iw-arrow { position: absolute; right: 11px; pointer-events: none; }
        .iw-arrow svg { width: 13px; height: 13px; stroke: #9ca3af; fill: none; }
        .iw-toggle {
            position: absolute; right: 8px;
            width: 26px; height: 26px; border-radius: 7px;
            background: none; border: none; cursor: pointer;
            display: flex; align-items: center; justify-content: center;
            color: #9ca3af; transition: color .15s, background .15s;
        }
        .iw-toggle:hover { color: #6b7280; background: #f3f4f6; }
        .iw-toggle svg { width: 13px; height: 13px; stroke: currentColor; fill: none; }

        /* Divider */
        .divider {
            display: flex; align-items: center; gap: 10px;
            margin: 4px 0 14px;
        }
        .divider::before, .divider::after { content: ''; flex: 1; height: 1px; background: #f1f5f9; }
        .divider span { font-size: 10px; font-weight: 700; color: #cbd5e1; white-space: nowrap; letter-spacing: .05em; text-transform: uppercase; }

        /* Submit */
        .btn-submit {
            width: 100%; margin-top: 6px; padding: 12px;
            border: none; border-radius: 13px;
            font-size: 14px; font-weight: 800; color: #fff; font-family: inherit;
            cursor: pointer; display: flex; align-items: center; justify-content: center; gap: 8px;
            background: linear-gradient(135deg, #3b82f6, #2563eb);
            box-shadow: 0 4px 16px rgba(37,99,235,.35);
            transition: transform .12s, box-shadow .12s;
            letter-spacing: -.01em;
        }
        .btn-submit:hover  { transform: translateY(-1px); box-shadow: 0 8px 24px rgba(37,99,235,.4); }
        .btn-submit:active { transform: scale(.98); }
        .btn-submit svg { width: 15px; height: 15px; stroke: #fff; fill: none; flex-shrink: 0; }

        /* Login link */
        .login-link {
            margin-top: 14px; padding-top: 13px;
            border-top: 1px solid #f1f5f9;
            text-align: center; font-size: 12.5px; color: #94a3b8; font-weight: 500;
        }
        .login-link a { color: #2563eb; font-weight: 700; text-decoration: none; margin-left: 2px; }
        .login-link a:hover { text-decoration: underline; }

        /* Footer strip */
        .form-footer {
            margin-top: 12px;
            text-align: center;
            font-size: 10.5px; color: #d1d5db; font-weight: 500;
        }
    </style>
</head>
